# FastAPI app-scoped client from contextlib import asynccontextmanager import httpx
@asynccontextmanager async def lifespan(app): app.state.http = httpx.AsyncClient(timeout=30.0) yield await app.state.http.aclose()
app = FastAPI(lifespan=lifespan)
@app.get("/proxy") async def proxy(request: Request): r = await request.app.state.http.get("https://upstream.example.com/data") return r.json()

class BackgroundTasks:
    def __init__(self):
        self.tasks: set[asyncio.Task] = set()

    def add(self, coro, *, name: str | None = None) -> asyncio.Task:
        task = asyncio.create_task(coro, name=name)
        self.tasks.add(task)
        task.add_done_callback(self.tasks.discard)
        return task

    async def shutdown(self, timeout: float = 5.0):
        for task in self.tasks:
            task.cancel()
        if self.tasks:
            await asyncio.wait(self.tasks, timeout=timeout)
